// Common Array problems

// 1. Two Sum - O(n) with HashMap

function twoSum(nums, target) {

  const map = new Map();

  for (let i = 0; i < nums.length; i++) {

    const complement = target - nums[i];

    if (map.has(complement)) return [map.get(complement), i];

    map.set(nums[i], i);

  }

  return [];

}

// 2. Maximum Subarray (Kadane's Algorithm) - O(n)

function maxSubArray(nums) {

  let maxSum = nums[0], currentSum = nums[0];

  for (let i = 1; i < nums.length; i++) {

    currentSum = Math.max(nums[i], currentSum + nums[i]);

    maxSum = Math.max(maxSum, currentSum);

  }

  return maxSum;

}

// Singly Linked List

class Node { constructor(val) { this.val = val; this.next = null; } }

class LinkedList {

  constructor() { this.head = null; this.size = 0; }

  // Insert at beginning O(1)

  prepend(val) {

    const node = new Node(val);

    node.next = this.head;

    this.head = node;

    this.size++;

  }

  // Reverse Linked List - classic problem

  reverse() {

    let prev = null, curr = this.head;

    while (curr) {

      const next = curr.next;

      curr.next = prev;

      prev = curr;

      curr = next;

    }

    this.head = prev;

  }

  // Detect cycle (Floyd's algorithm)

  hasCycle() {

    let slow = this.head, fast = this.head;

    while (fast && fast.next) {

      slow = slow.next;

      fast = fast.next.next;

      if (slow === fast) return true;

    }

    return false;

  }

}

// Stack applications

// 1. Valid Parentheses - O(n)

function isValid(s) {

  const stack = [];

  const pairs = { ')':'(', ']':'[', '}':'{' };

  for (const ch of s) {

    if ('([{'.includes(ch)) stack.push(ch);

    else if (stack.pop() !== pairs[ch]) return false;

  }

  return stack.length === 0;

}

// 2. Next Greater Element - O(n) Monotonic Stack

function nextGreater(arr) {

  const result = new Array(arr.length).fill(-1);

  const stack = []; // index stack

  for (let i = 0; i < arr.length; i++) {

    while (stack.length && arr[i] > arr[stack.at(-1)]) {

      result[stack.pop()] = arr[i];

    }

    stack.push(i);

  }

  return result;

}

// 3. Largest Rectangle in Histogram - O(n)

function largestRectangle(heights) {

  const stack = [], n = heights.length;

  let maxArea = 0;

  heights.push(0); // sentinel

  for (let i = 0; i <= n; i++) {

    while (stack.length && heights[i] < heights[stack.at(-1)]) {

      const h = heights[stack.pop()];

      const w = stack.length ? i - stack.at(-1) - 1 : i;

      maxArea = Math.max(maxArea, h * w);

    }

    stack.push(i);

  }

  return maxArea;

}

