// LRU Cache implementation

class LRUCache {

  constructor(capacity) {

    this.capacity = capacity;

    this.cache = new Map(); // Map giữ insertion order

  }

  get(key) {

    if (!this.cache.has(key)) return -1;

    const val = this.cache.get(key);

    this.cache.delete(key);

    this.cache.set(key, val); // move to end

    return val;

  }

  put(key, value) {

    if (this.cache.has(key)) this.cache.delete(key);

    else if (this.cache.size >= this.capacity)

      this.cache.delete(this.cache.keys().next().value); // remove LRU

    this.cache.set(key, value);

  }

}

// 1. Check Anagram - O(n)

function isAnagram(s, t) {

  if (s.length !== t.length) return false;

  const count = {};

  for (const c of s) count[c] = (count[c] || 0) + 1;

  for (const c of t) {

    if (!count[c]) return false;

    count[c]--;

  }

  return true;

}

// 2. Longest Substring Without Repeating - O(n) Sliding Window

function lengthOfLongestSubstring(s) {

  const seen = new Map();

  let maxLen = 0, left = 0;

  for (let right = 0; right < s.length; right++) {

    if (seen.has(s[right]) && seen.get(s[right]) >= left)

      left = seen.get(s[right]) + 1;

    seen.set(s[right], right);

    maxLen = Math.max(maxLen, right - left + 1);

  }

  return maxLen;

}

// 3. Valid Palindrome - O(n)

function isPalindrome(s) {

  const clean = s.toLowerCase().replace(/[^a-z0-9]/g, '');

  let l = 0, r = clean.length - 1;

  while (l < r) if (clean[l++] !== clean[r--]) return false;

  return true;

}

// Factorial

function factorial(n) {

  if (n <= 1) return 1;        // base case

  return n * factorial(n - 1); // recursive case

}

// Fibonacci - Memoized O(n)

function fib(n, memo = {}) {

  if (n <= 1) return n;

  if (memo[n]) return memo[n];

  return memo[n] = fib(n-1, memo) + fib(n-2, memo);

}

// Power of 2 (Divide & Conquer) - O(log n)

function power(base, exp) {

  if (exp === 0) return 1;

  if (exp % 2 === 0) {

    const half = power(base, exp / 2);

    return half * half;

  }

  return base * power(base, exp - 1);

}

