// N-Queens Problem

function solveNQueens(n) {

  const board = Array(n).fill().map(() => Array(n).fill('.'));

  const results = [];

  function isValid(row, col) {

    for (let r = 0; r < row; r++) {

      if (board[r][col] === 'Q') return false;

      if (col - (row - r) >= 0 && board[r][col - (row - r)] === 'Q') return false;

      if (col + (row - r) < n  && board[r][col + (row - r)] === 'Q') return false;

    }

    return true;

  }

  function backtrack(row) {

    if (row === n) { results.push(board.map(r => r.join(''))); return; }

    for (let col = 0; col < n; col++) {

      if (!isValid(row, col)) continue;

      board[row][col] = 'Q';

      backtrack(row + 1);

      board[row][col] = '.'; // backtrack

    }

  }

  backtrack(0);

  return results;

}

// Permutations

function permute(nums) {

  const result = [];

  function bt(start) {

    if (start === nums.length) { result.push([...nums]); return; }

    for (let i = start; i < nums.length; i++) {

      [nums[start], nums[i]] = [nums[i], nums[start]]; // swap

      bt(start + 1);

      [nums[start], nums[i]] = [nums[i], nums[start]]; // restore

    }

  }

  bt(0);

  return result;

}

// Fixed window: Maximum sum subarray of size k - O(n)

function maxSumSubarray(arr, k) {

  let windowSum = arr.slice(0, k).reduce((a, b) => a + b, 0);

  let maxSum = windowSum;

  for (let i = k; i < arr.length; i++) {

    windowSum += arr[i] - arr[i - k]; // slide

    maxSum = Math.max(maxSum, windowSum);

  }

  return maxSum;

}

// Variable window: Minimum window substring - O(n+m)

function minWindow(s, t) {

  const need = {}, have = {};

  for (const c of t) need[c] = (need[c] || 0) + 1;

  let formed = 0, required = Object.keys(need).length;

  let left = 0, minLen = Infinity, result = '';

  for (let right = 0; right < s.length; right++) {

    const c = s[right];

    have[c] = (have[c] || 0) + 1;

    if (need[c] && have[c] === need[c]) formed++;

    while (formed === required) {

      if (right - left + 1 < minLen) {

        minLen = right - left + 1;

        result = s.slice(left, right + 1);

      }

      have[s[left]]--;

      if (need[s[left]] && have[s[left]] < need[s[left]]) formed--;

      left++;

    }

  }

  return result;

}

// Two Sum (sorted array) - O(n)

function twoSumSorted(nums, target) {

  let left = 0, right = nums.length - 1;

  while (left < right) {

    const sum = nums[left] + nums[right];

    if (sum === target) return [left, right];

    if (sum < target) left++;

    else right--;

  }

  return [];

}

// Container with Most Water - O(n)

function maxArea(height) {

  let left = 0, right = height.length - 1, max = 0;

  while (left < right) {

    max = Math.max(max, Math.min(height[left], height[right]) * (right - left));

    if (height[left] < height[right]) left++;

    else right--;

  }

  return max;

}

// 3Sum - O(n^2)

function threeSum(nums) {

  nums.sort((a, b) => a - b);

  const result = [];

  for (let i = 0; i < nums.length - 2; i++) {

    if (i > 0 && nums[i] === nums[i-1]) continue; // skip dup

    let l = i + 1, r = nums.length - 1;

    while (l < r) {

      const sum = nums[i] + nums[l] + nums[r];

      if (sum === 0) {

        result.push([nums[i], nums[l++], nums[r--]]);

        while (l < r && nums[l] === nums[l-1]) l++;

      } else if (sum < 0) l++;

      else r--;

    }

  }

  return result;

}

// Build prefix sum - O(n)

function buildPrefix(arr) {

  const prefix = [0];

  for (const x of arr) prefix.push(prefix.at(-1) + x);

  return prefix;

}

// Range sum query O(1)

function rangeSum(prefix, l, r) {

  return prefix[r + 1] - prefix[l];

}

// Subarray Sum Equals K - O(n)

function subarraySum(nums, k) {

  const map = new Map([[0, 1]]); // prefix sum -> count

  let count = 0, prefixSum = 0;

  for (const n of nums) {

    prefixSum += n;

    count += (map.get(prefixSum - k) || 0);

    map.set(prefixSum, (map.get(prefixSum) || 0) + 1);

  }

  return count;

}

// Spiral order traversal - O(m*n)

function spiralOrder(matrix) {

  const result = [];

  let top = 0, bottom = matrix.length - 1;

  let left = 0, right = matrix[0].length - 1;

  while (top <= bottom && left <= right) {

    for (let i = left; i <= right; i++) result.push(matrix[top][i]);

    top++;

    for (let i = top; i <= bottom; i++) result.push(matrix[i][right]);

    right--;

    if (top <= bottom) {

      for (let i = right; i >= left; i--) result.push(matrix[bottom][i]);

      bottom--;

    }

    if (left <= right) {

      for (let i = bottom; i >= top; i--) result.push(matrix[i][left]);

      left++;

    }

  }

  return result;

}

// Rotate matrix 90 degrees in-place

function rotate(matrix) {

  const n = matrix.length;

  // Step 1: Transpose

  for (let i = 0; i < n; i++)

    for (let j = i + 1; j < n; j++)

      [matrix[i][j], matrix[j][i]] = [matrix[j][i], matrix[i][j]];

  // Step 2: Reverse each row

  for (const row of matrix) row.reverse();

}

