// MinHeap implementation

class MinHeap {

  constructor() { this.heap = []; }

  push(val) {

    this.heap.push(val);

    this._bubbleUp(this.heap.length - 1);

  }

  pop() {

    const min = this.heap[0];

    const last = this.heap.pop();

    if (this.heap.length) { this.heap[0] = last; this._siftDown(0); }

    return min;

  }

  _bubbleUp(i) {

    while (i > 0) {

      const parent = Math.floor((i - 1) / 2);

      if (this.heap[parent] > this.heap[i])

        [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];

      else break;

      i = parent;

    }

  }

  _siftDown(i) {

    const n = this.heap.length;

    while (true) {

      let smallest = i;

      const l = 2*i+1, r = 2*i+2;

      if (l < n && this.heap[l] < this.heap[smallest]) smallest = l;

      if (r < n && this.heap[r] < this.heap[smallest]) smallest = r;

      if (smallest === i) break;

      [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];

      i = smallest;

    }

  }

}

// K largest elements

function kLargest(nums, k) {

  const heap = new MinHeap();

  for (const n of nums) {

    heap.push(n);

    if (heap.heap.length > k) heap.pop();

  }

  return heap.heap;

}

// Detect cycle in linked list

function hasCycle(head) {

  let slow = head, fast = head;

  while (fast && fast.next) {

    slow = slow.next;

    fast = fast.next.next;

    if (slow === fast) return true;

  }

  return false;

}

// Find start of cycle

function detectCycle(head) {

  let slow = head, fast = head;

  while (fast && fast.next) {

    slow = slow.next;

    fast = fast.next.next;

    if (slow === fast) {

      slow = head; // reset slow to head

      while (slow !== fast) { slow = slow.next; fast = fast.next; }

      return slow; // start of cycle

    }

  }

  return null;

}

// Find middle of linked list

function findMiddle(head) {

  let slow = head, fast = head;

  while (fast && fast.next) {

    slow = slow.next;

    fast = fast.next.next;

  }

  return slow; // slow is at middle

}

// Daily Temperatures (Next Greater) - O(n)

function dailyTemperatures(temps) {

  const result = new Array(temps.length).fill(0);

  const stack = []; // index stack, monotonic decreasing

  for (let i = 0; i < temps.length; i++) {

    while (stack.length && temps[i] > temps[stack.at(-1)]) {

      const idx = stack.pop();

      result[idx] = i - idx;

    }

    stack.push(i);

  }

  return result;

}

// Trapping Rain Water - O(n)

function trap(height) {

  let left = 0, right = height.length - 1;

  let leftMax = 0, rightMax = 0, water = 0;

  while (left < right) {

    if (height[left] < height[right]) {

      height[left] >= leftMax ? (leftMax = height[left]) : (water += leftMax - height[left]);

      left++;

    } else {

      height[right] >= rightMax ? (rightMax = height[right]) : (water += rightMax - height[right]);

      right--;

    }

  }

  return water;

}

// Merge Overlapping Intervals - O(n log n)

function merge(intervals) {

  intervals.sort((a, b) => a[0] - b[0]);

  const result = [intervals[0]];

  for (let i = 1; i < intervals.length; i++) {

    const curr = intervals[i];

    const prev = result.at(-1);

    if (curr[0] <= prev[1]) prev[1] = Math.max(prev[1], curr[1]);

    else result.push(curr);

  }

  return result;

}

// Meeting Rooms II (Min Rooms Needed) - O(n log n)

function minMeetingRooms(intervals) {

  const starts = intervals.map(i => i[0]).sort((a,b) => a-b);

  const ends   = intervals.map(i => i[1]).sort((a,b) => a-b);

  let rooms = 0, maxRooms = 0, j = 0;

  for (let i = 0; i < intervals.length; i++) {

    if (starts[i] < ends[j]) { rooms++; maxRooms = Math.max(maxRooms, rooms); }

    else { rooms--; j++; }

  }

  return maxRooms;

}

