// In-order: Left -> Root -> Right (gives sorted order for BST)

function inorder(root) {

  const result = [];

  function dfs(node) {

    if (!node) return;

    dfs(node.left);

    result.push(node.val);

    dfs(node.right);

  }

  dfs(root);

  return result;

}

