  for (let i = 1; i <= n; i++)

    for (let j = 0; j < i; j++)

      if (isPalin[j][i-1]) dp[i] = Math.min(dp[i], dp[j]+1);

  return dp[n];

}

// Strange Printer - O(n^3)

function strangePrinter(s) {

  const n = s.length;

  const dp = Array.from({length:n}, ()=>new Array(n).fill(0));

  for (let i = n-1; i >= 0; i--) {

    dp[i][i] = 1;

    for (let j = i+1; j < n; j++) {

      dp[i][j] = dp[i+1][j] + 1; // print s[i] alone

      for (let k = i+1; k <= j; k++) {

        if (s[k] === s[i]) {

          dp[i][j] = Math.min(dp[i][j], dp[i][k-1] + (k+1<=j ? dp[k+1][j] : 0));

// Optionally: dp[i+1][k] + dp[k][j] variants

        }

      }

    }

  }

  return dp[0][n-1];

}

// Count paths in grid with obstacles - O(m*n)

function uniquePathsWithObstacles(grid) {

  const m = grid.length, n = grid[0].length;

  if (grid[0][0] === 1) return 0;

  const dp = Array.from({length:m}, ()=>new Array(n).fill(0));

  dp[0][0] = 1;

  for (let i = 0; i < m; i++)

    for (let j = 0; j < n; j++) {

      if (i===0 && j===0) continue;

      if (grid[i][j] === 1) dp[i][j] = 0;

      else dp[i][j] = (i>0?dp[i-1][j]:0) + (j>0?dp[i][j-1]:0);

    }

  return dp[m-1][n-1];

}

// Count BSTs with n nodes (Catalan number)

function numTrees(n) {

  const dp = new Array(n+1).fill(0);

  dp[0] = dp[1] = 1;

  for (let i = 2; i <= n; i++)

    for (let j = 1; j <= i; j++)

      dp[i] += dp[j-1] * dp[i-j];

  return dp[n];

}
